query CompanySafe($id: String!) {
      company(id: $id) { companyId contractDate isEDCReplicated }
    }

query JobAuthBuyer($id: String!) {
        jobAuthDetails(id: $id) {
          buyer {
            enterprise
            isPaymentMethodVerified
            info {
              company { companyId contractDate isEDCReplicated }
              location { city country countryTimezone }
              stats {
                score
                feedbackCount
                totalAssignments
                hoursCount
                totalCharges { amount }
                totalJobsWithHires
                activeAssignmentsCount
              }
            }
          }
        }
      }

query JobAuthCompName($id: String!) {
        jobAuthDetails(id: $id) {
          buyer { info { company { companyId name profile { industry size } } } }
        }
      }

query JobAuthFull($id: String!) {
        jobAuthDetails(id: $id) {
          buyer {
            enterprise
            isPaymentMethodVerified
            info {
              company { companyId contractDate isEDCReplicated name profile { industry size } }
              location { city country countryTimezone }
              stats { score feedbackCount totalAssignments totalCharges { amount } activeAssignmentsCount }
            }
            workHistory {
              contractorInfo { contractorName }
              jobInfo { title type }
              startDate endDate status totalCharge
              feedback { score comment }
            }
          }
          opening {
            job {
              info { title description }
              client { location { country } totalFeedback totalReviews }
            }
          }
          hiredApplicantNames
        }
      }

query {
      organization { id type legacyType flag { client vendor agency individual } }
      companySelector {
        items { organizationId title typeTitle organizationType monetizedTitle }
      }
    }

